pub mod db;
mod pty;
mod watcher;

#[cfg(debug_assertions)]
mod dev_bridge;

use pty::PtyManager;
use watcher::WatcherManager;
use std::path::Path;
use std::sync::Arc;
use tauri::menu::{MenuBuilder, SubmenuBuilder};
use tauri::{Emitter, Manager};
#[cfg(not(debug_assertions))]
use tauri_plugin_prevent_default::Flags;

#[cfg(target_os = "macos")]
use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};

#[tauri::command]
fn greet(name: &str) -> String {
    format!("Hello, {}! You've been greeted from Rust!", name)
}

/// Check if a directory is a valid harness project (contains .harness folder)
#[tauri::command]
fn check_harness_exists(path: String) -> bool {
    let harness_path = Path::new(&path).join(".harness");
    harness_path.is_dir()
}

/// Read project info from package.json if available
#[tauri::command]
fn get_project_info(path: String) -> Option<serde_json::Value> {
    let package_json_path = Path::new(&path).join("package.json");
    if package_json_path.exists() {
        if let Ok(contents) = std::fs::read_to_string(&package_json_path) {
            if let Ok(json) = serde_json::from_str::<serde_json::Value>(&contents) {
                return Some(json);
            }
        }
    }
    None
}

/// Run harness CLI command in a project directory
#[tauri::command]
fn run_harness_command(project_path: String, args: Vec<String>) -> Result<String, String> {
    use std::process::Command;

    // Get the harness binary path (same directory as this executable)
    let current_exe = std::env::current_exe().map_err(|e| e.to_string())?;
    let harness_path = current_exe.parent()
        .ok_or("Cannot find parent directory")?
        .join("harness");

    // Run harness command
    let output = Command::new(&harness_path)
        .current_dir(&project_path)
        .args(&args)
        .output()
        .map_err(|e| format!("Failed to run harness: {}", e))?;

    if output.status.success() {
        Ok(String::from_utf8_lossy(&output.stdout).to_string())
    } else {
        let stderr = String::from_utf8_lossy(&output.stderr);
        Err(format!("Harness command failed: {}", stderr))
    }
}

/// Get git info for a project (last commit)
#[tauri::command]
fn get_git_info(project_path: String) -> Result<String, String> {
    use std::process::Command;

    // Run git log to get the last commit
    let output = Command::new("git")
        .current_dir(&project_path)
        .args(["log", "-1", "--format=%H|%s|%an|%aI"])
        .output()
        .map_err(|e| format!("Failed to run git: {}", e))?;

    if !output.status.success() {
        return Err("Not a git repository".to_string());
    }

    let line = String::from_utf8_lossy(&output.stdout);
    let parts: Vec<&str> = line.trim().split('|').collect();

    if parts.len() >= 4 {
        let json = serde_json::json!({
            "hash": parts[0],
            "message": parts[1],
            "author": parts[2],
            "date": parts[3]
        });
        Ok(json.to_string())
    } else {
        Err("Failed to parse git output".to_string())
    }
}

/// Create native macOS-style application menu
fn setup_app_menu(app: &tauri::App) -> Result<(), Box<dyn std::error::Error>> {
    // HQ (App) menu - macOS first menu is always the app menu
    let app_menu = SubmenuBuilder::new(app, "HQ")
        .about(None)
        .separator()
        .text("settings", "Settings…")
        .separator()
        .services()
        .separator()
        .hide()
        .hide_others()
        .show_all()
        .separator()
        .quit()
        .build()?;

    // File menu
    let file_menu = SubmenuBuilder::new(app, "File")
        .text("open_project", "Open Project…")
        .separator()
        .text("new_tab", "New Tab")
        .text("close_tab", "Close Tab")
        .separator()
        .close_window()
        .build()?;

    // Edit menu
    let edit_menu = SubmenuBuilder::new(app, "Edit")
        .undo()
        .redo()
        .separator()
        .cut()
        .copy()
        .paste()
        .separator()
        .select_all()
        .build()?;

    // View menu
    let view_menu = SubmenuBuilder::new(app, "View")
        .text("toggle_sidebar", "Toggle Sidebar")
        .text("toggle_logs", "Toggle Logs")
        .separator()
        .fullscreen()
        .build()?;

    // Window menu
    let window_menu = SubmenuBuilder::new(app, "Window")
        .minimize()
        .maximize()
        .separator()
        .text("prev_tab", "Previous Tab")
        .text("next_tab", "Next Tab")
        .separator()
        .close_window()
        .build()?;

    // Help menu
    let help_menu = SubmenuBuilder::new(app, "Help")
        .text("documentation", "Documentation")
        .text("github", "GitHub Repository")
        .build()?;

    // Build the complete menu
    let menu = MenuBuilder::new(app)
        .items(&[
            &app_menu,
            &file_menu,
            &edit_menu,
            &view_menu,
            &window_menu,
            &help_menu,
        ])
        .build()?;

    // Set as global app menu
    app.set_menu(menu)?;

    Ok(())
}

/// Handle menu events
fn handle_menu_event(app: &tauri::AppHandle, event: tauri::menu::MenuEvent) {
    match event.id().0.as_str() {
        "settings" => {
            let _ = app.emit("menu:settings", ());
        }
        "open_project" => {
            let _ = app.emit("menu:open_project", ());
        }
        "new_tab" => {
            let _ = app.emit("menu:new_tab", ());
        }
        "close_tab" => {
            let _ = app.emit("menu:close_tab", ());
        }
        "toggle_sidebar" => {
            let _ = app.emit("menu:toggle_sidebar", ());
        }
        "toggle_logs" => {
            let _ = app.emit("menu:toggle_logs", ());
        }
        "prev_tab" => {
            let _ = app.emit("menu:prev_tab", ());
        }
        "next_tab" => {
            let _ = app.emit("menu:next_tab", ());
        }
        "documentation" => {
            // Open documentation URL
            let _ = open::that("https://github.com/your-org/hq#readme");
        }
        "github" => {
            // Open GitHub URL
            let _ = open::that("https://github.com/your-org/hq");
        }
        _ => {}
    }
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    let pty_manager = Arc::new(PtyManager::new());
    let watcher_manager = Arc::new(WatcherManager::new());

    // Start dev bridge in debug mode
    #[cfg(debug_assertions)]
    {
        let pty_for_bridge = pty_manager.clone();
        std::thread::spawn(move || {
            let rt = tokio::runtime::Runtime::new().unwrap();
            rt.block_on(async {
                let (_token, handle) = dev_bridge::start_dev_bridge(pty_for_bridge, None).await;
                handle.await.unwrap();
            });
        });
    }

    // Configure browser behavior prevention
    // In debug mode: disable prevent_default entirely for easier debugging
    // In release mode: disable browser shortcuts for native feel
    #[cfg(not(debug_assertions))]
    let prevent_default = tauri_plugin_prevent_default::Builder::new()
        .with_flags(Flags::all())
        .build();

    #[cfg(debug_assertions)]
    let builder = tauri::Builder::default()
        .plugin(tauri_plugin_shell::init())
        .plugin(tauri_plugin_dialog::init());

    #[cfg(not(debug_assertions))]
    let builder = tauri::Builder::default()
        .plugin(tauri_plugin_shell::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(prevent_default);

    builder
        .manage(pty_manager)
        .manage(watcher_manager)
        .setup(|app| {
            // Setup native menu bar
            if let Err(e) = setup_app_menu(app) {
                eprintln!("Failed to setup app menu: {}", e);
            }

            // Apply window vibrancy on macOS
            #[cfg(target_os = "macos")]
            {
                if let Some(window) = app.get_webview_window("main") {
                    // Use Sidebar material for a nice translucent effect
                    if let Err(e) = apply_vibrancy(&window, NSVisualEffectMaterial::Sidebar, None, None) {
                        eprintln!("Failed to apply vibrancy: {}", e);
                    }
                }
            }

            Ok(())
        })
        .on_menu_event(handle_menu_event)
        .invoke_handler(tauri::generate_handler![
            greet,
            check_harness_exists,
            get_project_info,
            run_harness_command,
            get_git_info,
            pty::pty_spawn,
            pty::pty_write,
            pty::pty_resize,
            pty::pty_kill,
            pty::pty_list,
            pty::pty_get,
            watcher::harness_watch_start,
            watcher::harness_watch_stop,
            watcher::harness_watch_list,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

//! Harness CLI - Database utility for AI agents and humans.
//!
//! This CLI provides programmatic access to the Harness storage layer,
//! enabling AI agents to manage tasks, progress, sessions, and screenshots.
//!
//! ## Usage
//!
//! ```bash
//! harness init                              # Create .harness/harness.db
//! harness db status                         # Show DB info
//! harness task add "Title" [-d "desc"]      # Add a task
//! harness task list [--status=TODO]         # List tasks
//! harness session start                     # Start work session
//! harness screenshot add "file.png" [-c "caption"]  # Add screenshot (F015)
//! ```

use clap::{Parser, Subcommand, ValueEnum};
use hq_lib::db;
use std::path::PathBuf;
use std::process::ExitCode;

// =============================================================================
// CLI STRUCTURE
// =============================================================================

#[derive(Parser)]
#[command(name = "harness")]
#[command(author, version, about = "Harness CLI - Database utility for AI agents")]
#[command(propagate_version = true)]
struct Cli {
    /// Output format
    #[arg(long, value_enum, global = true, default_value = "text")]
    format: OutputFormat,

    /// Project directory (defaults to current directory)
    #[arg(short = 'C', long, global = true)]
    dir: Option<PathBuf>,

    #[command(subcommand)]
    command: Commands,
}

#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
enum OutputFormat {
    /// Human-readable text
    Text,
    /// JSON for programmatic use
    Json,
    /// IDs only (one per line)
    Quiet,
}

#[derive(Subcommand)]
enum Commands {
    /// Initialize a new Harness project
    Init,

    /// Database operations
    Db {
        #[command(subcommand)]
        command: DbCommands,
    },

    /// Task management
    Task {
        #[command(subcommand)]
        command: TaskCommands,
    },

    /// Task step management
    Step {
        #[command(subcommand)]
        command: StepCommands,
    },

    /// Work session management
    Session {
        #[command(subcommand)]
        command: SessionCommands,
    },

    /// Progress log management
    Progress {
        #[command(subcommand)]
        command: ProgressCommands,
    },

    /// Embedding management (semantic search)
    Embeddings {
        #[command(subcommand)]
        command: EmbeddingsCommands,
    },

    /// Screenshot management (F015)
    Screenshot {
        #[command(subcommand)]
        command: ScreenshotCommands,
    },

    /// Show project status summary
    Status,
}

// -----------------------------------------------------------------------------
// DB Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum DbCommands {
    /// Show database status and statistics
    Status,
}

// -----------------------------------------------------------------------------
// Task Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum TaskCommands {
    /// Add a new task
    Add {
        /// Task title
        title: String,

        /// Task description
        #[arg(short, long)]
        description: Option<String>,

        /// Task category
        #[arg(short, long)]
        category: Option<String>,

        /// Initial status
        #[arg(short, long, value_enum, default_value = "backlog")]
        status: TaskStatusArg,
    },

    /// List tasks
    List {
        /// Filter by status
        #[arg(short, long, value_enum)]
        status: Option<TaskStatusArg>,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,

        /// Pagination cursor
        #[arg(long)]
        cursor: Option<String>,
    },

    /// Search tasks using semantic search (ordered by relevance)
    Search {
        /// Search query
        query: String,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },

    /// Get a task by ID
    Get {
        /// Task ID (ULID)
        id: String,
    },

    /// Update a task
    Update {
        /// Task ID (ULID)
        id: String,

        /// New title
        #[arg(short, long)]
        title: Option<String>,

        /// New description
        #[arg(short, long)]
        description: Option<String>,

        /// New category
        #[arg(short, long)]
        category: Option<String>,

        /// New status
        #[arg(long, value_enum)]
        status: Option<TaskStatusArg>,

        /// Mark as passed (true/false)
        #[arg(long)]
        passed: Option<bool>,
    },

    /// Delete a task
    Delete {
        /// Task ID (ULID)
        id: String,
    },

    /// Reorder a task
    Reorder {
        /// Task ID to move
        id: String,

        /// Place after this task ID
        #[arg(long)]
        after: String,
    },
}

#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
enum TaskStatusArg {
    Backlog,
    Todo,
    Doing,
    Review,
    Qa,
    Done,
}

impl From<TaskStatusArg> for db::TaskStatus {
    fn from(arg: TaskStatusArg) -> Self {
        match arg {
            TaskStatusArg::Backlog => db::TaskStatus::Backlog,
            TaskStatusArg::Todo => db::TaskStatus::Todo,
            TaskStatusArg::Doing => db::TaskStatus::Doing,
            TaskStatusArg::Review => db::TaskStatus::Review,
            TaskStatusArg::Qa => db::TaskStatus::Qa,
            TaskStatusArg::Done => db::TaskStatus::Done,
        }
    }
}

// -----------------------------------------------------------------------------
// Step Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum StepCommands {
    /// Add a step to a task
    Add {
        /// Parent task ID
        task_id: String,

        /// Step description
        description: String,
    },

    /// List steps for a task
    List {
        /// Parent task ID
        task_id: String,
    },

    /// Mark a step as complete
    Complete {
        /// Step ID
        id: String,
    },

    /// Mark a step as incomplete
    Uncomplete {
        /// Step ID
        id: String,
    },

    /// Toggle step completion
    Toggle {
        /// Step ID
        id: String,
    },

    /// Delete a step
    Delete {
        /// Step ID
        id: String,
    },
}

// -----------------------------------------------------------------------------
// Session Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum SessionCommands {
    /// Start a new work session
    Start {
        /// Session summary
        #[arg(short, long)]
        summary: Option<String>,
    },

    /// End the current session
    End {
        /// Final summary
        #[arg(short, long)]
        summary: Option<String>,
    },

    /// Show current active session
    Current,

    /// List sessions
    List {
        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,

        /// Pagination cursor
        #[arg(long)]
        cursor: Option<String>,
    },

    /// Get a session by ID
    Get {
        /// Session ID (ULID)
        id: String,
    },
}

// -----------------------------------------------------------------------------
// Progress Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum ProgressCommands {
    /// Add a progress entry
    Add {
        /// Progress content
        content: String,

        /// Session ID (uses current session if not specified)
        #[arg(short, long)]
        session: Option<String>,
    },

    /// List progress entries
    List {
        /// Filter by session ID
        #[arg(short, long)]
        session: Option<String>,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,

        /// Pagination cursor
        #[arg(long)]
        cursor: Option<String>,
    },

    /// Search progress using semantic search (ordered by relevance)
    Search {
        /// Search query
        query: String,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },
}

// -----------------------------------------------------------------------------
// Embeddings Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum EmbeddingsCommands {
    /// Show embedding statistics
    Status,

    /// Rebuild all embeddings from scratch
    Rebuild {
        /// Only rebuild task embeddings
        #[arg(long)]
        tasks_only: bool,

        /// Only rebuild progress embeddings
        #[arg(long)]
        progress_only: bool,
    },
}

// -----------------------------------------------------------------------------
// Screenshot Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum ScreenshotCommands {
    /// Add a screenshot record
    Add {
        /// File name (relative to .harness/screenshots/)
        file_name: String,

        /// Associated task ID
        #[arg(short, long)]
        task: Option<String>,

        /// Caption describing the screenshot
        #[arg(short, long)]
        caption: Option<String>,
    },

    /// List screenshots
    List {
        /// Filter by task ID
        #[arg(short, long)]
        task: Option<String>,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },

    /// Get a screenshot by ID
    Get {
        /// Screenshot ID (ULID)
        id: String,
    },

    /// Delete a screenshot record
    Delete {
        /// Screenshot ID (ULID)
        id: String,
    },

    /// Show screenshot statistics
    Stats,
}

// =============================================================================
// MAIN
// =============================================================================

fn main() -> ExitCode {
    let cli = Cli::parse();

    // Determine project directory
    let project_dir = cli.dir.unwrap_or_else(|| std::env::current_dir().unwrap_or_default());

    let result = match cli.command {
        Commands::Init => cmd_init(&project_dir, cli.format),
        Commands::Db { command } => match command {
            DbCommands::Status => cmd_db_status(&project_dir, cli.format),
        },
        Commands::Task { command } => cmd_task(&project_dir, command, cli.format),
        Commands::Step { command } => cmd_step(&project_dir, command, cli.format),
        Commands::Session { command } => cmd_session(&project_dir, command, cli.format),
        Commands::Progress { command } => cmd_progress(&project_dir, command, cli.format),
        Commands::Embeddings { command } => cmd_embeddings(&project_dir, command, cli.format),
        Commands::Screenshot { command } => cmd_screenshot(&project_dir, command, cli.format),
        Commands::Status => cmd_status(&project_dir, cli.format),
    };

    match result {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("Error: {}", e);
            match e {
                CliError::NotHarnessProject => ExitCode::from(2),
                CliError::Database(_) => ExitCode::from(3),
                _ => ExitCode::FAILURE,
            }
        }
    }
}

// =============================================================================
// ERROR HANDLING
// =============================================================================

#[derive(Debug)]
enum CliError {
    NotHarnessProject,
    Database(db::DbError),
    NotFound(String),
    NoActiveSession,
    Io(std::io::Error),
}

impl std::fmt::Display for CliError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            CliError::NotHarnessProject => write!(f, "Not a Harness project (no .harness/ folder)"),
            CliError::Database(e) => write!(f, "Database error: {}", e),
            CliError::NotFound(what) => write!(f, "Not found: {}", what),
            CliError::NoActiveSession => write!(f, "No active session"),
            CliError::Io(e) => write!(f, "IO error: {}", e),
        }
    }
}

impl From<db::DbError> for CliError {
    fn from(e: db::DbError) -> Self {
        CliError::Database(e)
    }
}

impl From<std::io::Error> for CliError {
    fn from(e: std::io::Error) -> Self {
        CliError::Io(e)
    }
}

type CliResult<T> = Result<T, CliError>;

// =============================================================================
// COMMAND IMPLEMENTATIONS
// =============================================================================

fn cmd_init(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
    let harness_dir = project_dir.join(db::HARNESS_FOLDER);

    // Create .harness/ if it doesn't exist
    if !harness_dir.exists() {
        std::fs::create_dir_all(&harness_dir)?;
    }

    // Open or create the database
    let conn = db::open_or_create(project_dir)?;

    let db_path = db::get_db_path(project_dir);

    match format {
        OutputFormat::Json => {
            println!(
                r#"{{"success":true,"path":"{}","version":"{}"}}"#,
                db_path.display(),
                db::SCHEMA_VERSION
            );
        }
        OutputFormat::Quiet => {
            println!("{}", db_path.display());
        }
        OutputFormat::Text => {
            println!("Initialized Harness database at {}", db_path.display());
            println!("Schema version: {}", db::SCHEMA_VERSION);

            // Show stats
            let stats = db::DbStats::collect(&conn, Some(&db_path))?;
            println!("\nDatabase stats:");
            println!("  Tasks:    {}", stats.task_count);
            println!("  Steps:    {}", stats.step_count);
            println!("  Sessions: {}", stats.session_count);
            println!("  Progress: {}", stats.progress_count);
        }
    }

    Ok(())
}

fn cmd_db_status(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;
    let db_path = db::get_db_path(project_dir);
    let stats = db::DbStats::collect(&conn, Some(&db_path))?;
    let version = db::get_schema_version(&conn)?.unwrap_or_else(|| "unknown".to_string());

    match format {
        OutputFormat::Json => {
            println!(
                r#"{{"path":"{}","version":"{}","size_bytes":{},"tasks":{},"steps":{},"sessions":{},"progress":{}}}"#,
                db_path.display(),
                version,
                stats.file_size_bytes,
                stats.task_count,
                stats.step_count,
                stats.session_count,
                stats.progress_count
            );
        }
        OutputFormat::Quiet => {
            println!("{}", db_path.display());
        }
        OutputFormat::Text => {
            println!("Database: {}", db_path.display());
            println!("Schema version: {}", version);
            println!("Size: {} bytes", stats.file_size_bytes);
            println!();
            println!("Counts:");
            println!("  Tasks:    {}", stats.task_count);
            println!("  Steps:    {}", stats.step_count);
            println!("  Sessions: {}", stats.session_count);
            println!("  Progress: {}", stats.progress_count);
        }
    }

    Ok(())
}

fn cmd_task(project_dir: &PathBuf, command: TaskCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        TaskCommands::Add {
            title,
            description,
            category,
            status,
        } => {
            let mut task = db::ProjectTask::new(&title).with_status(status.into());

            if let Some(ref desc) = description {
                task = task.with_description(desc);
            }
            if let Some(ref cat) = category {
                task = task.with_category(cat);
            }

            db::create_task(&conn, &task)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&task).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", task.id);
                }
                OutputFormat::Text => {
                    println!("Created task: {}", task.id);
                    println!("  Title:  {}", task.title);
                    println!("  Status: {}", task.status.as_str());
                }
            }
        }

        TaskCommands::List { status, limit, cursor } => {
            let result = if let Some(status) = status {
                db::list_tasks_by_status(&conn, status.into(), cursor.as_deref(), Some(limit))?
            } else {
                db::list_tasks(&conn, cursor.as_deref(), Some(limit))?
            };

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&result).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for task in &result.items {
                        println!("{}", task.id);
                    }
                }
                OutputFormat::Text => {
                    if result.items.is_empty() {
                        println!("No tasks found.");
                    } else {
                        println!("{:<26}  {:<8}  {}", "ID", "STATUS", "TITLE");
                        println!("{}", "-".repeat(70));
                        for task in &result.items {
                            println!(
                                "{:<26}  {:<8}  {}",
                                task.id,
                                task.status.as_str(),
                                truncate(&task.title, 32)
                            );
                        }
                        if result.has_next {
                            println!();
                            println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                        }
                    }
                }
            }
        }

        TaskCommands::Search { query, limit } => {
            // Use semantic search for relevance-ordered results
            let results = db::search_tasks_semantic(&conn, &query, Some(limit))?;

            match format {
                OutputFormat::Json => {
                    // Extract just tasks for JSON output
                    let tasks: Vec<_> = results.iter().map(|(t, _)| t).collect();
                    println!("{}", serde_json::to_string(&tasks).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for (task, _) in &results {
                        println!("{}", task.id);
                    }
                }
                OutputFormat::Text => {
                    if results.is_empty() {
                        println!("No tasks found matching '{}'.", query);
                    } else {
                        println!("Found {} task(s) matching '{}' (ordered by relevance):", results.len(), query);
                        println!();
                        println!("{:<26}  {:<8}  {:<6}  {}", "ID", "STATUS", "SCORE", "TITLE");
                        println!("{}", "-".repeat(80));
                        for (task, distance) in &results {
                            // Convert distance to similarity score (lower distance = higher score)
                            let score = 1.0 - distance.min(1.0);
                            println!(
                                "{:<26}  {:<8}  {:.3}   {}",
                                task.id,
                                task.status.as_str(),
                                score,
                                truncate(&task.title, 32)
                            );
                        }
                    }
                }
            }
        }

        TaskCommands::Get { id } => {
            let task = db::get_task(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Task {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&task).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", task.id);
                }
                OutputFormat::Text => {
                    println!("ID:          {}", task.id);
                    println!("Title:       {}", task.title);
                    println!("Status:      {}", task.status.as_str());
                    println!("Category:    {}", task.category.as_deref().unwrap_or("-"));
                    println!("Description: {}", task.description.as_deref().unwrap_or("-"));
                    println!("Passed:      {}", task.is_passed);
                    println!("Order:       {:.2}", task.sort_order);
                    println!("Created:     {}", task.created_at);
                    println!("Updated:     {}", task.updated_at);

                    // Show steps
                    let steps = db::list_steps(&conn, &id)?;
                    if !steps.is_empty() {
                        println!();
                        println!("Steps ({}):", steps.len());
                        for step in &steps {
                            let check = if step.is_completed { "[x]" } else { "[ ]" };
                            println!("  {} {}", check, step.description);
                        }
                    }
                }
            }
        }

        TaskCommands::Update {
            id,
            title,
            description,
            category,
            status,
            passed,
        } => {
            let mut update = db::TaskUpdate::default();
            update.title = title;
            update.description = description.map(Some);
            update.category = category.map(Some);
            update.status = status.map(|s| s.into());

            let updated = db::update_task(&conn, &id, update)?;

            if let Some(p) = passed {
                db::set_task_passed(&conn, &id, p)?;
            }

            if !updated && passed.is_none() {
                return Err(CliError::NotFound(format!("Task {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    if let Some(task) = db::get_task(&conn, &id)? {
                        println!("{}", serde_json::to_string(&task).unwrap_or_default());
                    }
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Updated task: {}", id);
                }
            }
        }

        TaskCommands::Delete { id } => {
            // Delete steps first
            db::delete_steps_for_task(&conn, &id)?;

            let deleted = db::delete_task(&conn, &id)?;
            if !deleted {
                return Err(CliError::NotFound(format!("Task {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"deleted":true,"id":"{}"}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Deleted task: {}", id);
                }
            }
        }

        TaskCommands::Reorder { id, after } => {
            let new_order = db::get_order_after(&conn, Some(&after))?;
            let mut update = db::TaskUpdate::default();
            update.sort_order = Some(new_order);

            let updated = db::update_task(&conn, &id, update)?;
            if !updated {
                return Err(CliError::NotFound(format!("Task {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","sort_order":{}}}"#, id, new_order);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Reordered task {} after {}", id, after);
                }
            }
        }
    }

    Ok(())
}

fn cmd_step(project_dir: &PathBuf, command: StepCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        StepCommands::Add { task_id, description } => {
            let step = db::add_step(&conn, &task_id, &description)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&step).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", step.id);
                }
                OutputFormat::Text => {
                    println!("Added step: {}", step.id);
                    println!("  Task:        {}", task_id);
                    println!("  Description: {}", step.description);
                }
            }
        }

        StepCommands::List { task_id } => {
            let steps = db::list_steps(&conn, &task_id)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&steps).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for step in &steps {
                        println!("{}", step.id);
                    }
                }
                OutputFormat::Text => {
                    if steps.is_empty() {
                        println!("No steps for task {}.", task_id);
                    } else {
                        println!("Steps for task {} ({}):", task_id, steps.len());
                        println!();
                        for step in &steps {
                            let check = if step.is_completed { "[x]" } else { "[ ]" };
                            println!("{} {} - {}", check, step.id, step.description);
                        }
                    }
                }
            }
        }

        StepCommands::Complete { id } => {
            let completed = db::complete_step(&conn, &id)?;
            if !completed {
                return Err(CliError::NotFound(format!("Step {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","is_completed":true}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Completed step: {}", id);
                }
            }
        }

        StepCommands::Uncomplete { id } => {
            let uncompleted = db::uncomplete_step(&conn, &id)?;
            if !uncompleted {
                return Err(CliError::NotFound(format!("Step {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","is_completed":false}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Uncompleted step: {}", id);
                }
            }
        }

        StepCommands::Toggle { id } => {
            // First get the step to check if it exists and get current state
            let step = db::get_step(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Step {}", id)))?;

            let new_state = !step.is_completed;
            db::set_step_completed(&conn, &id, new_state)?;

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","is_completed":{}}}"#, id, new_state);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    let state = if new_state { "completed" } else { "incomplete" };
                    println!("Step {} is now {}", id, state);
                }
            }
        }

        StepCommands::Delete { id } => {
            let deleted = db::delete_step(&conn, &id)?;
            if !deleted {
                return Err(CliError::NotFound(format!("Step {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"deleted":true,"id":"{}"}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Deleted step: {}", id);
                }
            }
        }
    }

    Ok(())
}

fn cmd_session(project_dir: &PathBuf, command: SessionCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        SessionCommands::Start { summary } => {
            let session = db::start_session(&conn, summary.as_deref())?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("Started session: {}", session.id);
                    if let Some(s) = &session.summary {
                        println!("  Summary: {}", s);
                    }
                    println!("  Started: {}", session.started_at);
                }
            }
        }

        SessionCommands::End { summary } => {
            let session_id = db::end_current_session(&conn, summary.as_deref())?
                .ok_or(CliError::NoActiveSession)?;

            match format {
                OutputFormat::Json => {
                    if let Some(session) = db::get_session(&conn, &session_id)? {
                        println!("{}", serde_json::to_string(&session).unwrap_or_default());
                    }
                }
                OutputFormat::Quiet => {
                    println!("{}", session_id);
                }
                OutputFormat::Text => {
                    println!("Ended session: {}", session_id);
                }
            }
        }

        SessionCommands::Current => {
            let session = db::get_current_session(&conn)?
                .ok_or(CliError::NoActiveSession)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("Current session: {}", session.id);
                    if let Some(s) = &session.summary {
                        println!("  Summary: {}", s);
                    }
                    println!("  Started: {}", session.started_at);

                    // Show progress count
                    let count = db::count_progress_for_session(&conn, &session.id)?;
                    println!("  Progress entries: {}", count);
                }
            }
        }

        SessionCommands::List { limit, cursor } => {
            let result = db::list_sessions(&conn, cursor.as_deref(), Some(limit))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&result).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for session in &result.items {
                        println!("{}", session.id);
                    }
                }
                OutputFormat::Text => {
                    if result.items.is_empty() {
                        println!("No sessions found.");
                    } else {
                        println!("{:<26}  {:<20}  {}", "ID", "STARTED", "STATUS");
                        println!("{}", "-".repeat(60));
                        for session in &result.items {
                            let status = if session.ended_at.is_some() { "ended" } else { "active" };
                            println!(
                                "{:<26}  {:<20}  {}",
                                session.id,
                                truncate(&session.started_at.to_string(), 20),
                                status
                            );
                        }
                        if result.has_next {
                            println!();
                            println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                        }
                    }
                }
            }
        }

        SessionCommands::Get { id } => {
            let session = db::get_session(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Session {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("ID:      {}", session.id);
                    println!("Summary: {}", session.summary.as_deref().unwrap_or("-"));
                    println!("Started: {}", session.started_at);
                    println!("Ended:   {}", session.ended_at.map(|d| d.to_string()).unwrap_or_else(|| "-".to_string()));

                    // Show progress entries
                    let progress = db::list_progress_for_session(&conn, &id)?;
                    if !progress.is_empty() {
                        println!();
                        println!("Progress ({}):", progress.len());
                        for entry in progress.iter().take(10) {
                            println!("  - {}", truncate(&entry.content, 60));
                        }
                        if progress.len() > 10 {
                            println!("  ... and {} more", progress.len() - 10);
                        }
                    }
                }
            }
        }
    }

    Ok(())
}

fn cmd_progress(project_dir: &PathBuf, command: ProgressCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        ProgressCommands::Add { content, session } => {
            // Use provided session or get current
            let session_id = match session {
                Some(id) => id,
                None => db::get_current_session(&conn)?
                    .ok_or(CliError::NoActiveSession)?
                    .id,
            };

            let progress = db::add_progress(&conn, &session_id, &content)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&progress).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", progress.id);
                }
                OutputFormat::Text => {
                    println!("Added progress: {}", progress.id);
                    println!("  Session: {}", session_id);
                    println!("  Content: {}", truncate(&content, 60));
                }
            }
        }

        ProgressCommands::List { session, limit, cursor } => {
            if let Some(session_id) = session {
                // List for specific session
                let entries = db::list_progress_for_session(&conn, &session_id)?;

                match format {
                    OutputFormat::Json => {
                        println!("{}", serde_json::to_string(&entries).unwrap_or_default());
                    }
                    OutputFormat::Quiet => {
                        for entry in &entries {
                            println!("{}", entry.id);
                        }
                    }
                    OutputFormat::Text => {
                        if entries.is_empty() {
                            println!("No progress entries for session {}.", session_id);
                        } else {
                            println!("Progress for session {} ({}):", session_id, entries.len());
                            println!();
                            for entry in &entries {
                                println!("[{}] {}", entry.created_at.format("%H:%M:%S"), entry.content);
                            }
                        }
                    }
                }
            } else {
                // List all with pagination
                let result = db::list_progress(&conn, cursor.as_deref(), Some(limit))?;

                match format {
                    OutputFormat::Json => {
                        println!("{}", serde_json::to_string(&result).unwrap_or_default());
                    }
                    OutputFormat::Quiet => {
                        for entry in &result.items {
                            println!("{}", entry.id);
                        }
                    }
                    OutputFormat::Text => {
                        if result.items.is_empty() {
                            println!("No progress entries found.");
                        } else {
                            for entry in &result.items {
                                println!("[{}] {}", entry.created_at.format("%Y-%m-%d %H:%M"), entry.content);
                            }
                            if result.has_next {
                                println!();
                                println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                            }
                        }
                    }
                }
            }
        }

        ProgressCommands::Search { query, limit } => {
            // Use semantic search for relevance-ordered results
            let results = db::search_progress_semantic(&conn, &query, Some(limit))?;

            match format {
                OutputFormat::Json => {
                    // Extract just entries for JSON output
                    let entries: Vec<_> = results.iter().map(|(e, _)| e).collect();
                    println!("{}", serde_json::to_string(&entries).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for (entry, _) in &results {
                        println!("{}", entry.id);
                    }
                }
                OutputFormat::Text => {
                    if results.is_empty() {
                        println!("No progress entries found matching '{}'.", query);
                    } else {
                        println!("Found {} entry(ies) matching '{}' (ordered by relevance):", results.len(), query);
                        println!();
                        for (entry, distance) in &results {
                            let score = 1.0 - distance.min(1.0);
                            println!("[{} | {:.2}] {}", entry.created_at.format("%Y-%m-%d %H:%M"), score, entry.content);
                        }
                    }
                }
            }
        }
    }

    Ok(())
}

fn cmd_embeddings(project_dir: &PathBuf, command: EmbeddingsCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        EmbeddingsCommands::Status => {
            let stats = db::EmbeddingStats::collect(&conn)?;

            match format {
                OutputFormat::Json => {
                    println!(
                        r#"{{"task_embeddings":{},"progress_embeddings":{},"service_loaded":{}}}"#,
                        stats.task_embeddings,
                        stats.progress_embeddings,
                        stats.service_loaded
                    );
                }
                OutputFormat::Quiet => {
                    println!("{}/{}", stats.task_embeddings, stats.progress_embeddings);
                }
                OutputFormat::Text => {
                    println!("Embedding Statistics");
                    println!("====================");
                    println!();
                    println!("Task embeddings:     {}", stats.task_embeddings);
                    println!("Progress embeddings: {}", stats.progress_embeddings);
                    println!("Model loaded:        {}", if stats.service_loaded { "yes" } else { "no" });
                }
            }
        }

        EmbeddingsCommands::Rebuild { tasks_only, progress_only } => {
            let (tasks_count, progress_count) = if tasks_only {
                let count = db::rebuild_task_embeddings(&conn)?;
                (count, 0)
            } else if progress_only {
                let count = db::rebuild_progress_embeddings(&conn)?;
                (0, count)
            } else {
                let t = db::rebuild_task_embeddings(&conn)?;
                let p = db::rebuild_progress_embeddings(&conn)?;
                (t, p)
            };

            match format {
                OutputFormat::Json => {
                    println!(
                        r#"{{"tasks_rebuilt":{},"progress_rebuilt":{}}}"#,
                        tasks_count, progress_count
                    );
                }
                OutputFormat::Quiet => {
                    println!("{}/{}", tasks_count, progress_count);
                }
                OutputFormat::Text => {
                    println!("Embeddings rebuilt:");
                    println!("  Tasks:    {}", tasks_count);
                    println!("  Progress: {}", progress_count);
                }
            }
        }
    }

    Ok(())
}

fn cmd_screenshot(project_dir: &PathBuf, command: ScreenshotCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        ScreenshotCommands::Add { file_name, task, caption } => {
            let mut screenshot = db::TestScreenshot::new(&file_name);

            if let Some(ref task_id) = task {
                screenshot = screenshot.with_task_id(task_id);
            }
            if let Some(ref cap) = caption {
                screenshot = screenshot.with_caption(cap);
            }

            db::create_screenshot(&conn, &screenshot)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&screenshot).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", screenshot.id);
                }
                OutputFormat::Text => {
                    println!("Added screenshot: {}", screenshot.id);
                    println!("  File:    {}", screenshot.file_name);
                    if let Some(ref t) = screenshot.task_id {
                        println!("  Task:    {}", t);
                    }
                    if let Some(ref c) = screenshot.caption {
                        println!("  Caption: {}", c);
                    }
                }
            }
        }

        ScreenshotCommands::List { task, limit } => {
            let screenshots = if let Some(ref task_id) = task {
                db::list_screenshots_for_task(&conn, task_id, Some(limit))?
            } else {
                db::list_screenshots(&conn, Some(limit))?
            };

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&screenshots).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for s in &screenshots {
                        println!("{}", s.id);
                    }
                }
                OutputFormat::Text => {
                    if screenshots.is_empty() {
                        println!("No screenshots found.");
                    } else {
                        println!("{:<26}  {:<30}  {}", "ID", "FILE", "CAPTION");
                        println!("{}", "-".repeat(80));
                        for s in &screenshots {
                            println!(
                                "{:<26}  {:<30}  {}",
                                s.id,
                                truncate(&s.file_name, 30),
                                truncate(s.caption.as_deref().unwrap_or("-"), 20)
                            );
                        }
                    }
                }
            }
        }

        ScreenshotCommands::Get { id } => {
            let screenshot = db::get_screenshot(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Screenshot {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&screenshot).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", screenshot.id);
                }
                OutputFormat::Text => {
                    println!("ID:       {}", screenshot.id);
                    println!("File:     {}", screenshot.file_name);
                    println!("Task:     {}", screenshot.task_id.as_deref().unwrap_or("-"));
                    println!("Step:     {}", screenshot.step_id.as_deref().unwrap_or("-"));
                    println!("Caption:  {}", screenshot.caption.as_deref().unwrap_or("-"));
                    println!("Created:  {}", screenshot.created_at);
                }
            }
        }

        ScreenshotCommands::Delete { id } => {
            let deleted = db::delete_screenshot(&conn, &id)?;
            if !deleted {
                return Err(CliError::NotFound(format!("Screenshot {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"deleted":true,"id":"{}"}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Deleted screenshot: {}", id);
                }
            }
        }

        ScreenshotCommands::Stats => {
            let total = db::count_screenshots(&conn)?;

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"total":{}}}"#, total);
                }
                OutputFormat::Quiet => {
                    println!("{}", total);
                }
                OutputFormat::Text => {
                    println!("Screenshot Statistics");
                    println!("=====================");
                    println!();
                    println!("Total screenshots: {}", total);
                }
            }
        }
    }

    Ok(())
}

fn cmd_status(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    // Collect counts by status using the HashMap
    let status_counts = db::count_tasks_by_status(&conn)?;
    let backlog = status_counts.get("BACKLOG").copied().unwrap_or(0);
    let todo = status_counts.get("TODO").copied().unwrap_or(0);
    let doing = status_counts.get("DOING").copied().unwrap_or(0);
    let review = status_counts.get("REVIEW").copied().unwrap_or(0);
    let qa = status_counts.get("QA").copied().unwrap_or(0);
    let done = status_counts.get("DONE").copied().unwrap_or(0);
    let total = backlog + todo + doing + review + qa + done;

    let active_sessions = db::count_active_sessions(&conn)?;
    let total_sessions = db::count_sessions(&conn)?;
    let total_progress = db::count_progress(&conn)?;

    match format {
        OutputFormat::Json => {
            println!(
                r#"{{"tasks":{{"backlog":{},"todo":{},"doing":{},"review":{},"qa":{},"done":{},"total":{}}},"sessions":{{"active":{},"total":{}}},"progress":{}}}"#,
                backlog, todo, doing, review, qa, done, total,
                active_sessions, total_sessions,
                total_progress
            );
        }
        OutputFormat::Quiet => {
            println!("{}/{}", done, total);
        }
        OutputFormat::Text => {
            println!("Project Status");
            println!("==============");
            println!();
            println!("Tasks: {}/{} complete", done, total);
            println!();
            println!("  BACKLOG:  {}", backlog);
            println!("  TODO:     {}", todo);
            println!("  DOING:    {}", doing);
            println!("  REVIEW:   {}", review);
            println!("  QA:       {}", qa);
            println!("  DONE:     {}", done);
            println!();
            println!("Sessions: {} total ({} active)", total_sessions, active_sessions);
            println!("Progress entries: {}", total_progress);
        }
    }

    Ok(())
}

// =============================================================================
// HELPERS
// =============================================================================

fn truncate(s: &str, max_len: usize) -> String {
    if s.len() <= max_len {
        s.to_string()
    } else {
        format!("{}...", &s[..max_len.saturating_sub(3)])
    }
}

